namespace sv_f7393922268749298da405eb79dea180.Services;

/// <summary>
/// Scoped service (per-circuit in Blazor Server) that holds the currently
/// selected warehouse and notifies all subscribed components when it changes.
/// </summary>
public sealed class WarehouseStateService
{
    public static readonly IReadOnlyList<(string Id, string Name)> Warehouses =
    [
        ("WH-001", "Warehouse A — Main Distribution"),
        ("WH-002", "Warehouse B — East Regional"),
        ("WH-003", "Warehouse C — West Regional"),
        ("WH-004", "Warehouse D — Cold Storage"),
    ];

    private string _currentWarehouseId = Warehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        Warehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId)
            return;

        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_f7393922268749298da405eb79dea180.Services;

/// <summary>
/// Scoped service (per-circuit) that tracks low-stock alert counts.
/// Components call <see cref="RefreshAsync"/> to poll; the service caches
/// the latest count and raises <see cref="OnChange"/> so every subscriber
/// updates — not just the component that triggered the refresh.
/// </summary>
public sealed class InventoryAlertService
{
    private readonly WarehouseStateService _warehouseState;
    private readonly Random _random = new();

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
    }

    public int CurrentAlertCount { get; private set; }

    public event Action? OnChange;

    /// <summary>
    /// Simulates a database query returning a random number between 0 and 15.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Fetches the latest alert count for the current warehouse,
    /// caches it, and notifies all subscribers.
    /// </summary>
    public async Task RefreshAsync()
    {
        CurrentAlertCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        OnChange?.Invoke();
    }
}

