@using sv_f7393922268749298da405eb79dea180.Services
@inject WarehouseStateService WarehouseState
@implements IDisposable

<div class="warehouse-selector d-flex align-items-center gap-2">
    <label for="warehouse-select" class="text-nowrap fw-semibold mb-0">📦 Warehouse:</label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            style="max-width: 280px;"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var (id, name) in WarehouseStateService.Warehouses)
        {
            <option value="@id">@name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(newId))
        {
            WarehouseState.SetWarehouse(newId);
        }
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@using sv_f7393922268749298da405eb79dea180.Services
@inject InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.CurrentAlertCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@AlertService.CurrentAlertCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-auto">0</span>
}

@code {
    protected override void OnInitialized()
    {
        AlertService.OnChange += OnAlertChanged;
    }

    private void OnAlertChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnChange -= OnAlertChanged;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_f7393922268749298da405eb79dea180.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">Current Site</h5>
        <p class="card-text fs-5">
            📦 <strong>@WarehouseState.CurrentWarehouseName</strong>
            <span class="text-muted">(@WarehouseState.CurrentWarehouseId)</span>
        </p>
    </div>
</div>

<div class="row g-4">
    <div class="col-md-4">
        <div class="card text-bg-@(AlertService.CurrentAlertCount > 0 ? "danger" : "success")">
            <div class="card-body text-center">
                <h2 class="display-4">@AlertService.CurrentAlertCount</h2>
                <p class="card-text">Low-Stock Alerts</p>
                <small>Polling every 10 seconds</small>
            </div>
        </div>
    </div>

    <div class="col-md-8">
        <div class="card">
            <div class="card-header">Alert Log</div>
            <ul class="list-group list-group-flush">
                @if (_alertLog.Count == 0)
                {
                    <li class="list-group-item text-muted">Waiting for first poll…</li>
                }
