+
+<PageTitle>Dashboard — @WarehouseState.CurrentWarehouseName</PageTitle>
+
+<h1>Warehouse Dashboard</h1>
+
+<div class="card mb-4">
+    <div class="card-body">
+        <h5 class="card-title">Current Site</h5>
+        <p class="card-text fs-5">
+            📦 <strong>@WarehouseState.CurrentWarehouseName</strong>
+            <span class="text-muted">(@WarehouseState.CurrentWarehouseId)</span>
+        </p>
+    </div>
+</div>
+
+<div class="row g-4">
+    <div class="col-md-4">
+        <div class="card text-bg-@(AlertService.CurrentAlertCount > 0 ? "danger" : "success")">
+            <div class="card-body text-center">
+                <h2 class="display-4">@AlertService.CurrentAlertCount</h2>
+                <p class="card-text">Low-Stock Alerts</p>
+                <small>Polling every 10 seconds</small>
+            </div>
+        </div>
+    </div>
+
+    <div class="col-md-8">
+        <div class="card">
+            <div class="card-header">Alert Log</div>
+            <ul class="list-group list-group-flush">
+                @if (_alertLog.Count == 0)
+                {
+                    <li class="list-group-item text-muted">Waiting for first poll…</li>
+                }
+                else
+                {
+                    @foreach (var entry in _alertLog.AsEnumerable().Reverse().Take(10))
+                    {
+                        <li class="list-group-item d-flex justify-content-between">
+                            <span>@entry.Warehouse</span>
+                            <span>
+                                <span class="badge bg-@(entry.Count > 0 ? "warning text-dark" : "success")">
+                                    @entry.Count items
+                                </span>
+                                <small class="text-muted ms-2">@entry.Time.ToString("HH:mm:ss")</small>
+                            </span>
+                        </li>
+                    }
+                }
+            </ul>
+        </div>
+    </div>
+</div>
+
+@code {
+    private Timer? _pollingTimer;
+    private readonly List<AlertLogEntry> _alertLog = new();
+
+    protected override void OnInitialized()
+    {
+        WarehouseState.OnChange += OnWarehouseChanged;
+        AlertService.OnChange += OnAlertChanged;
+    }
+
+    protected override async Task OnAfterRenderAsync(bool firstRender)
+    {
+        if (firstRender)
+        {
+            // Fetch immediately, then start the 10-second polling cycle.
+            await AlertService.RefreshAsync();
+            LogCurrentAlert();
+            StateHasChanged();
+
+            _pollingTimer = new Timer(async _ =>
+            {
+                await AlertService.RefreshAsync();
+                LogCurrentAlert();
+                await InvokeAsync(StateHasChanged);
+            }, null, TimeSpan.FromSeconds(10), TimeSpan.FromSeconds(10));
+        }
+    }
+
+    private async void OnWarehouseChanged()
+    {
+        // Immediately refresh alerts when warehouse changes.
+        await AlertService.RefreshAsync();
+        LogCurrentAlert();
+        await InvokeAsync(StateHasChanged);
+    }
+
+    private void OnAlertChanged()
+    {
+        InvokeAsync(StateHasChanged);
+    }
+
+    private void LogCurrentAlert()
+    {
+        _alertLog.Add(new AlertLogEntry(
+            WarehouseState.CurrentWarehouseName,
+            AlertService.CurrentAlertCount,
+            DateTime.Now));
+    }
+
+    public void Dispose()
+    {
+        _pollingTimer?.Dispose();
+        WarehouseState.OnChange -= OnWarehouseChanged;
+        AlertService.OnChange -= OnAlertChanged;
+    }
+
+    private record AlertLogEntry(string Warehouse, int Count, DateTime Time);
+}
